parameters.jsCode:
const input = items[0].json;

// Reconstitution des articles à partir de l'agrégateur
const articles = input.title.map((t, index) => ({
    title: t,
    link: input.link[index],
    source_name: input.source_name[index],
    pub_date: input.pub_date[index],
    axe: input.axe[index],
    summary_ai: input.summary_ai ? input.summary_ai[index] : "Résumé non disponible."
}));

// Configuration visuelle par axe selon les thématiques du projet
const axesConfig = {
    axe_actualite: { label: "Actualité IA & Enseignement", color: "#f97316" }, // Orange
    axe_contexte: { label: "Suisse Romande & Institutions", color: "#dc2626" }, // Rouge
    axe_legal: { label: "Cadre Légal & Réglementation", color: "#9333ea" },    // Violet
    axe_outils: { label: "Solutions & Outils IA", color: "#16a34a" }           // Vert
};

let sectionsHtml = "";

for (const [id, config] of Object.entries(axesConfig)) {
    const axeArticles = articles.filter(art => art.axe === id);

    if (axeArticles.length > 0) {
        sectionsHtml += `
            <h2 style="color: ${config.color}; border-bottom: 2px solid ${config.color}; padding-bottom: 5px; text-transform: uppercase; font-size: 15px; margin-top: 40px; letter-spacing: 1px;">
                ${config.label}
            </h2>`;

        axeArticles.forEach(art => {
            sectionsHtml += `
                <div style="margin-bottom: 25px; padding: 15px; border-left: 4px solid ${config.color}; background-color: #ffffff; border-radius: 0 8px 8px 0;">
                    <h3 style="margin-top: 0; color: #111827; font-size: 18px; line-height: 1.3;">${art.title}</h3>
                    <p style="font-size: 11px; color: #6b7280; text-transform: uppercase; margin-bottom: 12px;">Source: ${art.source_name} | ${art.pub_date}</p>
                    <div style="background-color: #f8fafc; padding: 12px; border-radius: 6px; font-style: italic; font-size: 14px; margin: 12px 0; border: 1px solid #e2e8f0; color: #334155; line-height: 1.5;">
                        <strong style="color: ${config.color};">Note pédagogique :</strong> ${art.summary_ai}
                    </div>
                    <a href="${art.link}" style="display: inline-block; background-color: ${config.color}; color: white; padding: 10px 18px; text-decoration: none; border-radius: 5px; font-size: 13px; font-weight: bold;">Lire l'article complet</a>
                </div>`;
        });
    }
}

const finalHtml = `
<div style="font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif; max-width: 650px; margin: auto; color: #333; background-color: #f4f4f7; padding: 20px;">
    <div style="background-color: #1e3a8a; padding: 45px 20px; text-align: center; color: white; border-radius: 12px 12px 0 0;">
        <h1 style="margin: 0; font-size: 30px; font-weight: 800; letter-spacing: 2px;">ATHÉNA IA HUB</h1>
        <p style="margin: 10px 0 0; opacity: 0.9; font-size: 16px; font-weight: 300;">Veille stratégique pour le Secondaire II</p>
    </div>

    <div style="background-color: white; padding: 30px 25px; border-radius: 0 0 12px 12px; box-shadow: 0 4px 15px rgba(0,0,0,0.05);">
        <p style="color: #4b5563; font-size: 15px; line-height: 1.6;">Bonjour,<br><br>Voici les ressources clés sélectionnées pour vous cette semaine par l'équipe Athéna.</p>
        ${sectionsHtml}
    </div>

    <div style="text-align: center; padding: 30px; font-size: 12px; color: #9ca3af; line-height: 1.5;">
        Cette veille automatisée est un projet de la Haute École de Gestion de Genève.<br>
        © 2026 Athéna IA Hub. Tous droits réservés.
    </div>
</div>`;

return [{ html: finalHtml }];
